Extension factory structure (src/index.ts):

export default function(pi: ExtensionAPI) {
  const state = new BridgeState(); // holds client, actorId, pollingTimer, seenIds

  pi.on("session_start", async (event, ctx) => {
    const config = loadConfig(); // env + .pi config
    if (!config.groupId) return; // inert when unconfigured

    try {
      await state.connect(config);
      await state.registerActor();
      state.startPolling(pi);
      ctx.ui.setStatus("cccc", "connected");
      ctx.ui.notify("CCCC bridge connected", "info");
    } catch (err) {
      ctx.ui.notify(`CCCC bridge: ${err.message}`, "error");
      ctx.ui.setStatus("cccc", "disconnected");
    }
  });

  pi.on("session_shutdown", async () => {
    state.stopPolling();
    await state.disconnect();
  });
}

BridgeState class encapsulates all mutable state and lifecycle.
Config loading reads: CCCC_DAEMON_HOST, CCCC_DAEMON_PORT, CCCC_GROUP_ID, CCCC_ACTOR_ID, CCCC_POLL_INTERVAL_MS.
